(function(outputs, steps, params, stepResult, assertEqual) {

    describe("RequestBuilder::stripCredentials Unit Tests", () => {
        const builder = new x_neyu_rest_utils.RequestBuilder();

        it("Should not strip non-auth related values", () => {
            const testMap = {
                "Content-Type": "application/json",
                "Accept": "application/json"
            };
            const strippedMap = builder.stripCredentials(testMap);
            Object.entries(strippedMap).forEach(([k, v]) => {
                expect(v).toEqual(testMap[k]);
            });
        });

        it("Should strip Bearer Auth credentials", () => {
            const testMap = {
                "Authorization": "Bearer aosdifjiawefjksdajdf"
            };
            const strippedMap = builder.stripCredentials(testMap);
            expect(strippedMap["Authorization"]).not.toEqual(testMap["Authorization"]);
            expect(strippedMap["Authorization"].indexOf("*")).toBe(7);
        });

		it("Should strip Basic Auth credentials", () => {
            const testMap = {
                "Authorization": "aosdifjiawefjksdajdf"
            };
            const strippedMap = builder.stripCredentials(testMap);
            expect(strippedMap["Authorization"]).not.toEqual(testMap["Authorization"]);
            expect(strippedMap["Authorization"].indexOf("*")).toBe(0);
        });
    });

})(outputs, steps, params, stepResult, assertEqual);
// uncomment the next line to execute this script as a jasmine test
jasmine.getEnv().execute();
